  --lvr-font-size-fluid-2: clamp(1.5rem, 6vw, 2.5rem);
  --lvr-font-size-fluid-3: clamp(2rem, 9vw, 3.5rem);

  /* Line heights — 00 (tight headings) through 5 (loose prose) */
  --lvr-font-lineheight-00: 0.95;
  --lvr-font-lineheight-0: 1.1;
